import { useState } from "react";

const TodoModal = function (isModalOpen, handleModal, setTodos) {
    <Modal isModalOpen={isModalOpen} cl={"todo-modal"}>
        <TodoModalHTML handleModal={handleModal} setTodos={setTodos} />
    </Modal>;
};
const AlertModal = function (toggleAlert, handleAlert, setTodos) {
    <Modal isModalOpen={toggleAlert} cl={"alert-modal"}>
        <AlertModalHTML handleAlert={handleAlert} />
    </Modal>;
};

const Modal = function ({ isModalOpen, cl, children }) {
    return (
        <>
            <div className={isModalOpen ? `${cl}` : "hidden"}>{children}</div>
        </>
    );
};
const TodoModalHTML = function ({ handleModal, setTodos }) {
    const [main, setMain] = useState("");
    const [sub, setSub] = useState("");
    const [start, setStart] = useState(null);
    const [deadline, setDeadLine] = useState(null);
    const newTodo = { main, sub, start, deadline };
    const handleNewTodo = function () {
        setTodos((todos) => [...todos, newTodo]);
    };

    return (
        <>
            <button type="button" className="todo-modal--close" onClick={handleModal}>
                &times;
            </button>
            <div className="input">
                <input
                    type="text"
                    className="input--main"
                    placeholder="main"
                    onChange={(e) => setMain(e.target.value)}
                />
                <input type="text" className="input--sub" placeholder="sub" onChange={(e) => setSub(e.target.value)} />
                <input
                    type="date"
                    className="input--start"
                    placeholder="start"
                    onChange={(e) => setStart(e.target.value)}
                />
                <input
                    type="date"
                    className="input--deadline"
                    placeholder="deadline"
                    onChange={(e) => setDeadLine(e.target.value)}
                />
            </div>
            <button type="button" className="add-new-todo-btn" onClick={handleNewTodo}>
                追加
            </button>
        </>
    );
};
const AlertModalHTML = function ({ handleAlert }) {
    return (
        <>
            <button type="button" class="alert-modal--close" onClick={handleAlert}>
                &times;
            </button>
        </>
    );
};
export { TodoModal, AlertModal };
